question:
次のコードを実行したとき、console.log(name) の出力はどれか？

const { name, age } = { name: "Taro", age: 20 };
console.log(name);

次のコードを実行したとき、console.log(age) の出力はどれか？

const { age, name } = { name: "Taro", age: 20 };
console.log(age);

次のコードを実行したとき、console.log(userName) の出力はどれか？

const { name: userName } = { name: "Hanako" };
console.log(userName);

次のコードを実行したとき、console.log(score) の出力はどれか？

const { score = 100 } = {};
console.log(score);

次のコードを実行したとき、console.log(score) の出力はどれか？

const { score = 100 } = { score: null };
console.log(score);

次のコードを実行したとき、console.log(a) の出力はどれか？

const [a, b] = [10, 20, 30];
console.log(a);

次のコードを実行したとき、console.log(second) の出力はどれか？

const [, second] = [10, 20, 30];
console.log(second);

次のコードを実行したとき、console.log(x) の出力はどれか？

const [x = 5] = [];
console.log(x);

次のコードを実行したとき、console.log(city) の出力はどれか？

const { address: { city } } = { address: { city: "Tokyo", zip: "100" } };
console.log(city);

次のコードを実行したとき、console.log(...) の出力はどれか？

function greet({ name, greeting = "Hello" }) {
  return `${greeting}, ${name}!`;
}
console.log(greet({ name: "Taro" }));

次のコードを実行したとき、console.log(JSON.stringify(rest)) の出力はどれか？

const { a, ...rest } = { a: 1, b: 2, c: 3 };
console.log(JSON.stringify(rest));

次のコードを実行したとき、console.log(JSON.stringify(others)) の出力はどれか？

const [first, ...others] = [1, 2, 3, 4];
console.log(JSON.stringify(others));

次のコードを実行したとき、console.log(x, y) の出力はどれか？

let x = 1, y = 2;
[x, y] = [y, x];
console.log(x, y);

次のコードを実行したとき、console.log(...) の出力はどれか？

function display({ name: fullName, age: years }) {
  return `${fullName} is ${years} years old`;
}
console.log(display({ name: "Hanako", age: 25 }));

次のコードを実行したとき、console.log(third) の出力はどれか？

const [,, third] = [10, 20, 30, 40];
console.log(third);

次のコードを実行したとき、console.log(x) の出力はどれか？

const { x } = { a: 1 };
console.log(x);

次のコードを実行したとき、console.log(name) の出力はどれか？

const [{ name }] = [{ name: "Taro", age: 20 }];
console.log(name);

次のコードを実行したとき、console.log(c) の出力はどれか？

const { a: { b: [c] } } = { a: { b: [1, 2, 3] } };
console.log(c);

次のコードを実行したとき、出力はどれか？

const users = [
  { id: 1, name: "Taro" },
  { id: 2, name: "Hanako" }
];
for (const { name } of users) {
  console.log(name);
}

次のコードを実行したとき、console.log(num) の出力はどれか？

const { x: num = 10 } = {};
console.log(num);

次のコードを実行したとき、console.log(value) の出力はどれか？

const key = "name";
const { [key]: value } = { name: "Taro" };
console.log(value);

次のコードを実行したとき、console.log(x + y) の出力はどれか？

function getPoint() {
  return { x: 3, y: 4 };
}
const { x, y } = getPoint();
console.log(x + y);

次のコードを実行したとき、console.log(b) の出力はどれか？

const { a: { b = 5 } = {} } = {};
console.log(b);

次のコードを実行したとき、console.log(first) の出力はどれか？

const [first, second] = "hello world".split(" ");
console.log(first);

次のコードを実行したとき、console.log(...) の出力はどれか？

function process({ items: [first, ...rest], meta: { total } }) {
  return `${first} of ${total}`;
}
console.log(process({ items: [10, 20, 30], meta: { total: 3 } }));
